// // This is a 4-to-2 decoder that converts a 4-bit input to a 2-bit one-hot output.
module decoder_2to4(IN, OUT);
input [1:0] IN;
output reg [3:0] OUT;

always @(*) begin
    case(IN)
        2'b00: OUT = 4'b0001;
        2'b01: OUT = 4'b0010;
        2'b10: OUT = 4'b0100;
        2'b11: OUT = 4'b1000;
        default: OUT = 4'b0000;
    endcase
end

endmodule
